    void formatNoStringArg(AstNode* argp, char ch) {
        if (argp && argp->isString()) {
            argp->v3error("$display-line format of '%"s + ch + "' illegal with string argument\n"
                          << argp->warnMore() << "... Suggest use '%s'");
        }
    }

